package com.hospital.management.filter;
import org.junit.jupiter.api.Test;import javax.servlet.FilterChain;import javax.servlet.http.*;import static org.mockito.Mockito.*;
class AuthenticationFilterTest {@Test void redirectsAnonymous()throws Exception{HttpServletRequest q=mock(HttpServletRequest.class);HttpServletResponse r=mock(HttpServletResponse.class);HttpSession s=mock(HttpSession.class);when(q.getSession(false)).thenReturn(null);when(q.getSession(true)).thenReturn(s);when(q.getContextPath()).thenReturn("/app");when(q.getRequestURI()).thenReturn("/app/dashboard");new AuthenticationFilter().doFilter(q,r,mock(FilterChain.class));verify(r).sendRedirect("/app/login");}@Test void continuesAuthenticated()throws Exception{HttpServletRequest q=mock(HttpServletRequest.class);HttpServletResponse r=mock(HttpServletResponse.class);HttpSession s=mock(HttpSession.class);FilterChain c=mock(FilterChain.class);when(q.getSession(false)).thenReturn(s);when(s.getAttribute("authenticatedUser")).thenReturn(new Object());new AuthenticationFilter().doFilter(q,r,c);verify(c).doFilter(q,r);}}
